import * as vscode from 'vscode';
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic(); // reads ANTHROPIC_API_KEY from env

/**
 * InlineCompletionProvider that calls Claude to fill in code at the cursor.
 * Registered as a VS Code inline completion provider.
 */
export class CopilotProvider implements vscode.InlineCompletionItemProvider {
  async provideInlineCompletionItems(
    document: vscode.TextDocument,
    position: vscode.Position,
    context: vscode.InlineCompletionContext,
    token: vscode.CancellationToken,
  ): Promise<vscode.InlineCompletionList> {
    // Collect the 60 lines before and 20 lines after the cursor.
    const startLine = Math.max(0, position.line - 60);
    const endLine = Math.min(document.lineCount - 1, position.line + 20);

    const prefix = document.getText(
      new vscode.Range(startLine, 0, position.line, position.character),
    );
    const suffix = document.getText(
      new vscode.Range(position.line, position.character, endLine, 0),
    );

    // Use fill-in-the-middle prompt format.
    const prompt = [
      `<fim_prefix>${prefix}`,
      `<fim_suffix>${suffix}`,
      `<fim_middle>`,  // model generates what belongs here
    ].join('');

    try {
      const response = await client.messages.create({
        model: 'claude-haiku-4-5',  // fastest model for low-latency completions
        max_tokens: 256,
        messages: [{ role: 'user', content: prompt }],
        system: 'You are a code completion engine. Output only the code that belongs at the cursor. No explanation, no markdown fences.',
      });

      const completion = response.content[0].type === 'text'
        ? response.content[0].text
        : '';

      if (!completion || token.isCancellationRequested) {
        return { items: [] };
      }

      return {
        items: [
          new vscode.InlineCompletionItem(
            completion,
            new vscode.Range(position, position),
          ),
        ],
      };
    } catch {
      return { items: [] };
    }
  }
}

// Extension activation: register the provider.
export function activate(context: vscode.ExtensionContext): void {
  const provider = new CopilotProvider();
  context.subscriptions.push(
    vscode.languages.registerInlineCompletionItemProvider(
      { pattern: '**' },  // all files
      provider,
    ),
  );
}

